1	const PROCESSING_FEE = 5;
2	const RUNE_BLOCK_SIZE = 3;
3	const RUNE_BLOCK_PRICE = 60;
4	
5	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	};
12	
13	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
14	
15	export function quote(input: { yearsWithMHPCO: number; items: Item[] }): number {
16	  const runeCount = input.items.filter((item) => item.type === "rune").length;
17	  const nonRuneItemsBase = input.items
18	    .filter((item) => item.type !== "rune")
19	    .reduce((sum, item) => sum + BASE_PREMIUM_BY_ITEM_TYPE[item.type], 0);
20	  const runesBase = runeCount === RUNE_BLOCK_SIZE
21	    ? RUNE_BLOCK_PRICE
22	    : runeCount * BASE_PREMIUM_BY_ITEM_TYPE.rune;
23	  return nonRuneItemsBase + runesBase + PROCESSING_FEE;
24	}
